import coap
import machine

# Create CoAP server
server = coap.CoapServer()

# Sensor values
temp = 25

# Actuator state
light = False

# Define sensor resource
@server.handle('GET', '/sensors/temp')
def get_temp(request):
    return coap.Message(payload=str(temp).encode())

# Define actuator resource
@server.handle('PUT', '/actuators/light')
def set_light(request):
    global light
    light = request.payload.decode() == 'true'
    return coap.Message()

# Run CoAP server
server.run()